 50→void BQ24297_InitHardware(                                                  
 51→                        tBQ24297Config *pConfigInit,                        
 52→                        tBQ24297WriteVars *pWriteInit,                      
 53→                        tBQ24297Data *pDataInit) {
 54→    pConfigBQ24 = pConfigInit;
 55→    pWriteVariables = pWriteInit;
 56→    pData = pDataInit;
 57→
 58→    // Create I2C mutex for cross-task synchronization
 59→    if (i2cMutex == NULL) {
 60→        i2cMutex = xSemaphoreCreateMutex();
 61→        if (i2cMutex == NULL) {
 62→            LOG_E("BQ24297_InitHardware: failed to create I2C mutex");
 63→            pData->initComplete = false;
 64→            return;
 65→        }
 66→    }
 67→
 68→    // Battery management initialization (hardware interface)
 69→
 70→    // ***Disable I2C calls*** as Harmony 2.06 doesn't have a working, 
 71→    // interrupt-safe implementation
 72→    // Open the I2C Driver for Master
 73→    pData->I2C_Handle = DRV_I2C_Open(                                       
 74→                        pConfigBQ24->I2C_Index,                             
 75→                        DRV_IO_INTENT_READWRITE|DRV_IO_INTENT_BLOCKING);
 76→
 77→    // Drive OTG LOW — DPDM will set 100mA (conservative).
 78→    // ManageIINLIM state machine overrides IINLIM via I2C after DPDM completes.
 79→    BATT_MAN_OTG_OutputEnable();
 80→    BATT_MAN_OTG_Clear();
 81→}
 82→
 83→bool BQ24297_ReadFaultReg(uint8_t *latched, uint8_t *current) {
 84→    uint8_t latchedVal = BQ24297_Read_I2C(0x09);
 85→    if (latchedVal == 0xFF) {
 86→        return false;  // First read failed — don't touch any fields
 87→    }
 88→
 89→    // Accumulate faults from the latched read
 90→    AccumulateFaults(latchedVal);
 91→    if (latched != NULL) *latched = latchedVal;
 92→
 93→    // Second read gets currently active faults
 94→    uint8_t currentVal = BQ24297_Read_I2C(0x09);
 95→    if (currentVal == 0xFF) {
 96→        // Second read failed — use latched value for status fields
 97→        LOG_E("BQ24297_ReadFaultReg: second REG09 read failed, using latched");
 98→        currentVal = latchedVal;
 99→    } else {
100→        AccumulateFaults(currentVal);
101→    }
102→
103→    if (current != NULL) *current = currentVal;
104→
105→    // Decode current value into status fields (existing behavior)
106→    pData->status.watchdog_fault = (bool)(currentVal & 0x80);
107→    pData->status.otg_fault = (bool)(currentVal & 0x40);
108→    pData->status.chgFault = (enum eChargeFault)((currentVal >> 4) & 0x03);
109→    pData->status.bat_fault = (bool)(currentVal & 0x08);
110→    pData->status.ntcFault = (enum eNTCFault)(currentVal & 0x03);
111→
112→    return true;
113→}
114→
115→void BQ24297_ClearAccumulatedFaults(void) {
116→    pData->status.watchdog_faultAccum = false;
117→    pData->status.otg_faultAccum = false;
118→    pData->status.chgFaultAccum = CHG_FAULT_NORMAL;
119→    pData->status.bat_faultAccum = false;
120→    pData->status.ntcFaultAccum = NTC_FAULT_NORMAL;
121→}
