123→void BQ24297_Config_Settings(void) {
124→    // Temporary value to hold current register value
125→    uint8_t reg = 0;
126→    
127→    LOG_D("BQ24297_Config_Settings: Starting initialization");
128→    
129→    // Read initial status to determine current power state
130→    BQ24297_UpdateStatus();
131→
132→    // Read REG00 to preserve current limit settings
133→    reg = BQ24297_Read_I2C(0x00);
134→    
135→    // Clear HIZ mode if set - it can cause power loss
136→    if (reg & 0x80) {
137→        LOG_D("BQ24297_Config_Settings: Clearing HIZ mode");
138→    }
139→
140→    // Set input voltage limit to 3.88V (minimum): VINDPM = 0
141→    // This gives maximum headroom before input voltage regulation kicks in
142→    // REG00: [7]=0 (CLEAR HIZ), [6:3]=0000 (3.88V min), [2:0]=keep current limit
143→    BQ24297_Write_I2C(0x00, reg & 0b00000111);  // This also clears HIZ bit
144→
145→    // Configure REG01 for charging mode
146→    // REG01 bits:
147→    // [7:6] = 01 (reset watchdog)
148→    // [5] = 0 (OTG disable)
149→    // [4] = 1 (CHARGE ENABLE)
150→    // [3:1] = 000 (SYS_MIN = 3.0V)
151→    // [0] = 1 (reserved)
152→    
153→    // Drive OTG LOW — DPDM sets 100mA (conservative), ManageIINLIM overrides via I2C
154→    BATT_MAN_OTG_OutputEnable();
155→    BATT_MAN_OTG_Clear();
156→
157→    // Configure for charge mode with SYS_MIN=3.0V to prevent BATFET disable
158→    BQ24297_Write_I2C(0x01, 0b01010001);  // Watchdog reset, OTG=0, CHG=1, SYS_MIN=3.0V
159→
160→    // Set fast charge to 2000mA - this should never need to be updated
161→    BQ24297_Write_I2C(0x02, 0b01100000);
162→    
163→    // REG03: Pre-charge and termination current
164→    // Set minimum termination current (128mA) to avoid premature termination
165→    // [7:5]=000 (128mA precharge), [4]=0 (reserved), [3:0]=0001 (128mA termination)
166→    BQ24297_Write_I2C(0x03, 0b00000001);
167→
168→    // REG04: Charge voltage and battery thresholds
169→    // [7:2]=100101 (4.096V), [1]=1 (3.0V battery low), [0]=0 (100mV recharge)
170→    // Set BATLOWV to 3.0V (higher threshold) to keep BATFET enabled longer
171→    BQ24297_Write_I2C(0x04, 0b10010110);
172→
173→    // REG05: Disable watchdog and maximize charge timer
174→    // [7]=1 (enable termination), [6]=0 (disable timer), [5:4]=00 (disable watchdog)
175→    // [3]=0 (normal), [2:1]=11 (20hr timer), [0]=0 (reserved)
176→    // CRITICAL: Watchdog disabled to prevent unexpected BATFET disable
177→    BQ24297_Write_I2C(0x05, 0b10001110);
178→    
179→    // REG06: Boost voltage and thermal regulation
180→    // [7:4]=0111 (4.998V boost), [3:2]=00 (reserved), [1:0]=11 (120C thermal limit)
181→    // Keep default boost voltage but set highest thermal limit
182→    BQ24297_Write_I2C(0x06, 0b01110011);
183→    
184→    // Ensure BATFET is enabled (REG07 bit 5 = 0)
185→    // Without BATFET, there's no path from battery to system
186→    reg = BQ24297_Read_I2C(0x07);
187→    if (reg & 0b00100000) {  // Check if bit 5 is set (BATFET disabled)
188→        reg = reg & 0b11011111;  // Clear bit 5 to enable BATFET
189→        BQ24297_Write_I2C(0x07, reg);
190→        LOG_D("BQ24297: BATFET re-enabled");
191→    }
192→
193→    // Read the current status
194→    BQ24297_UpdateStatus();
195→
196→    // Start with conservative 500mA IINLIM
197→    // BQ24297_ManageIINLIM() state machine will adjust based on USB enumeration
198→    BQ24297_SetIINLIM(ILim_500);
199→    pData->iinlimState = IINLIM_STATE_IDLE;
200→    pData->iinlimTimestamp = 0;
201→    pData->iinlimLastVbus = false;
202→
203→    // Update battery presence and charging-allowed flag based on NTC status.
204→    // NTC_FAULT_COLD = no battery (open thermistor) → chargeAllowed=false
205→    // NTC_FAULT_HOT  = unsafe temperature            → chargeAllowed=false
206→    BQ24297_UpdateBatteryStatus();
207→
208→    // REG01 was written with CHG=1 above, so unconditionally enforce the
209→    // charge-allowed decision — disable charging via I2C if NTC fault present.
210→    BQ24297_ChargeEnable(pData->chargeAllowed);
211→    if (!pData->chargeAllowed) {
212→        LOG_E("BQ24297: Charging disabled at boot (NTC=%d, batPresent=%d)",
213→              pData->status.ntcFault, pData->status.batPresent);
214→    }
215→
216→    // Clear accumulated faults from init reads — start fresh
217→    BQ24297_ClearAccumulatedFaults();
218→
219→    // Mark initialization complete
220→    pData->initComplete = true;
221→    
222→    LOG_D("BQ24297_Config_Settings: Initialization complete");
223→}
224→
225→/*
226→ * Updates BQ24297 status by reading all registers via I2C.
227→ * Called at boot, and on-demand by ForceDPDM, DisableOTG,
228→ * IsBatteryPresent, and UpdateBatteryStatus.
229→ */
230→void BQ24297_UpdateStatus(void) {
231→
232→    uint8_t regData = 0;
233→    bool hasErrors = false;
234→
235→    // REG00: Input Source Control
236→    regData = BQ24297_Read_I2C(0x00);
237→    if (regData != 0xFF) {
238→        pData->status.hiZ = (bool) (regData & 0b10000000);
239→        pData->status.inLim = (uint8_t) (regData & 0b00000111);
240→    } else {
241→        hasErrors = true;
242→    }
243→
244→    // REG01: Power-On Configuration
245→    regData = BQ24297_Read_I2C(0x01);
246→    if (regData != 0xFF) {
247→        pData->status.otg = (bool) (regData & 0b00100000);
248→        pData->status.chgEn = (bool) (regData & 0b00010000);
249→    } else {
250→        hasErrors = true;
251→    }
252→
253→    // REG02: Charge Current Control
254→    regData = BQ24297_Read_I2C(0x02);
255→    if (regData != 0xFF) {
256→        pData->status.ichg = (uint8_t) (regData & 0b11111100) >> 2;
257→    } else {
258→        hasErrors = true;
259→    }
260→
261→    // REG07: Misc Operation Control
262→    regData = BQ24297_Read_I2C(0x07);
263→    if (regData != 0xFF) {
264→        pData->status.iinDet_Read = (bool) (regData & 0b10000000);
265→    } else {
266→        hasErrors = true;
267→    }
268→
269→    // REG08: System Status
270→    regData = BQ24297_Read_I2C(0x08);
271→    if (regData != 0xFF) {
272→        pData->status.vBusStat = (uint8_t) (regData & 0b11000000) >> 6;
273→        pData->status.chgStat = (uint8_t) (regData & 0b00110000) >> 4;
274→        pData->status.dpmStat = (bool) (regData & 0b00001000);
275→        pData->status.pgStat = (bool) (regData & 0b00000100);
276→        pData->status.thermStat = (bool) (regData & 0b00000010);
277→        pData->status.vsysStat = (bool) (regData & 0b00000001);
278→        
279→        // vsysStat = 1 means battery voltage < VSYSMIN (3.0V)
280→        // This is critical for power-up decisions
281→        // Only log status changes to reduce log spam
282→        static uint8_t lastReg08 = 0xFF;
283→        if (regData != lastReg08) {
284→            LOG_D("BQ24297: REG08=0x%02X vsysStat=%d (batt %s 3.0V) pgStat=%d vBusStat=%d", 
285→                  regData, pData->status.vsysStat, 
286→                  pData->status.vsysStat ? "<" : ">", 
287→                  pData->status.pgStat, pData->status.vBusStat);
288→                  
289→            // Extra logging when vsysStat indicates low battery
290→            if (pData->status.vsysStat) {
291→                LOG_D("BQ24297: Battery voltage < 3.0V (vsysStat=1)");
292→            }
293→            
294→            lastReg08 = regData;
295→        }
296→    } else {
297→        hasErrors = true;
298→    }
299→
300→    // REG09: Fault Status — use centralized reader that accumulates faults
301→    if (!BQ24297_ReadFaultReg(NULL, NULL)) {
302→        hasErrors = true;
303→    }
304→    
305→    if (hasErrors) {
306→        LOG_E("BQ24297_UpdateStatus: I2C communication errors detected");
307→    }
308→    
309→    // Check for critical faults
310→    if (pData->status.bat_fault) {
311→        LOG_E("BQ24297: BATFET fault - battery disconnected from system!");
312→    }
313→}
314→
315→void BQ24297_ChargeEnable(bool chargeEnable) {
316→    uint8_t reg = BQ24297_Read_I2C(0x01);
317→
318→    if (reg == 0xFF) {
319→        LOG_E("BQ24297_ChargeEnable: REG01 read failed, cannot %s charging",
320→              chargeEnable ? "enable" : "disable");
321→        return;
322→    }
323→
324→    // OTG and Charge are mutually exclusive
325→    if (reg & 0x20) {
326→        return;  // OTG is enabled, cannot modify charge state
327→    }
328→
329→    if (pData->chargeAllowed && chargeEnable && pData->status.batPresent) {
330→        reg = (reg & 0b11101111) | 0b00010000;
331→        BQ24297_Write_I2C(0x01, reg);
332→    } else {
333→        reg = (reg & 0b11101111);
334→        BQ24297_Write_I2C(0x01, reg);
335→    }
336→}
337→
338→void BQ24297_ForceDPDM(void) {
339→    uint8_t reg = 0;
340→    // WARNING: Forcing DPDM while connected via USB will disrupt USB comms
341→    // and may require physical cable replug. Only safe from wall charger or UART.
342→
343→    reg = BQ24297_Read_I2C(0x07);
344→    if (reg == 0xFF) {
345→        LOG_E("BQ24297_ForceDPDM: REG07 read failed");
346→        return;
347→    }
348→
349→    // Force DPDM detection — REG07 bit 7
350→    if (!BQ24297_Write_I2C(0x07, reg | 0x80)) {
351→        LOG_E("BQ24297_ForceDPDM: REG07 write failed");
352→        return;
353→    }
354→
355→    const TickType_t start = xTaskGetTickCount();
356→    const TickType_t timeoutTicks = pdMS_TO_TICKS(2000);
357→
358→    for (;;) {
359→        BQ24297_UpdateStatus();
360→
361→        if (!pData->status.iinDet_Read) {
362→            break;
363→        }
364→
365→        if ((xTaskGetTickCount() - start) > timeoutTicks) {
366→            LOG_E("BQ24297_ForceDPDM: timeout waiting for DPDM to complete");
367→            break;
368→        }
369→
370→        vTaskDelay(pdMS_TO_TICKS(50));
371→    }
372→}
373→
374→void BQ24297_AutoSetILim(void) {
375→    // Temporary value to hold current register value
376→    uint8_t reg0;
377→
378→    reg0 = BQ24297_Read_I2C(0x00);
379→    
380→    // Log if HIZ mode is detected during AutoSetILim
381→    if (reg0 & 0x80) {
382→        LOG_E("BQ24297_AutoSetILim: WARNING - HIZ mode detected (REG00=0x%02X)! Will be cleared.", reg0);
383→    }
384→
385→    //  Set system input current
386→    // CRITICAL: Never preserve HIZ bit (bit 7) when writing to REG00!
387→    // Use mask 0b01111000 instead of 0b11111000 to clear HIZ
388→    switch (pData->status.vBusStat) {
389→        case 0b00:
390→            // Unknown - assume it is a charger. Set IINLIM to 2000mA       
391→            //- maximum allowed on charger
392→            BQ24297_Write_I2C(0x00, 0b00000110 | (reg0 & 0b01111000));
393→            break;
394→        case 0b01:
395→            // NOTE: Originally set to 500mA for USB 2.0 compliance, but this
396→            // caused audible whining from the power supply. Using 2A instead.
397→            // Most modern USB ports can handle this, especially with enumeration.
398→            // Original 500mA setting:
399→            // BQ24297_Write_I2C(0x00, 0b00000010 | (reg0 & 0b01111000));
400→            BQ24297_Write_I2C(0x00, 0b00000110 | (reg0 & 0b01111000));
401→            break;
402→        case 0b10:
403→            // Unknown - assume it is a charger. Set IINLIM to 2000mA 
404→            //maximum allowed on charger
405→            BQ24297_Write_I2C(0x00, 0b00000110 | (reg0 & 0b01111000));
406→            break;
407→        default:
408→            break;
409→    }
410→}
411→
412→uint8_t BQ24297_Read_I2C(uint8_t reg) {
413→    uint8_t I2CData[1];
414→    uint8_t rxData = 0;
415→
416→    if (pData->I2C_Handle == DRV_HANDLE_INVALID) {
417→        LOG_E("BQ24297_Read_I2C: Invalid I2C handle");
418→        return 0xFF;
419→    }
420→
421→    if (i2cMutex != NULL) {
422→        xSemaphoreTake(i2cMutex, portMAX_DELAY);
423→    }
424→
425→    // Build data packet
426→    I2CData[0] = reg;
427→
428→    // Perform I2C transfer with error checking
429→    bool success = DRV_I2C_WriteReadTransfer(pData->I2C_Handle,
430→            pConfigBQ24->I2C_Address,
431→            I2CData,
432→            1,
433→            &rxData,
434→            1);
435→
436→    if (i2cMutex != NULL) {
437→        xSemaphoreGive(i2cMutex);
438→    }
439→
440→    if (!success) {
441→        LOG_E("BQ24297_Read_I2C: Failed to read register 0x%02X", reg);
442→        return 0xFF;
443→    }
444→
445→    return rxData;
446→}
447→
448→bool BQ24297_Write_I2C(uint8_t reg, uint8_t txData) {
449→    uint8_t I2CData[2];
450→
451→    if (pData->I2C_Handle == DRV_HANDLE_INVALID) {
452→        LOG_E("BQ24297_Write_I2C: Invalid I2C handle");
453→        return false;
454→    }
455→
456→    if (i2cMutex != NULL) {
457→        xSemaphoreTake(i2cMutex, portMAX_DELAY);
458→    }
459→
460→    // Build data packet
461→    I2CData[0] = reg;
462→    I2CData[1] = txData;
463→
464→    // Write to selected register with error checking
465→    bool success = DRV_I2C_WriteTransfer(
466→                    pData->I2C_Handle,
467→                    pConfigBQ24->I2C_Address,
468→                    I2CData,
469→                    2);
470→
471→    if (i2cMutex != NULL) {
472→        xSemaphoreGive(i2cMutex);
473→    }
474→
475→    if (!success) {
476→        LOG_E("BQ24297_Write_I2C: Failed to write 0x%02X to register 0x%02X", txData, reg);
477→    }
478→
479→    return success;
480→}
481→
482→bool BQ24297_SetIINLIM(uint8_t iinlimCode) {
483→    // REG00 IINLIM is 3-bit field (bits 2:0), valid range 0-7 per datasheet Table 9-2
484→    if (iinlimCode > ILim_3000) return false;
485→    uint8_t reg = BQ24297_Read_I2C(0x00);
486→    if (reg == 0xFF) return false;
487→    // Clear HIZ (bit 7) and IINLIM (bits 2:0), preserve VINDPM (bits 6:3)
488→    reg = (reg & 0b01111000) | (iinlimCode & 0x07);
489→    bool success = BQ24297_Write_I2C(0x00, reg);
490→    if (!success) {
491→        LOG_E("BQ24297_SetIINLIM: Failed to write IINLIM code %u", iinlimCode);
492→    }
493→    return success;
494→}
495→
496→void BQ24297_ManageIINLIM(bool vbusPresent) {
497→    TickType_t now = xTaskGetTickCount();
498→
499→    switch (pData->iinlimState) {
500→        case IINLIM_STATE_IDLE:
501→            if (vbusPresent && !pData->iinlimLastVbus) {
502→                // Rising edge — VBUS just appeared
503→                LOG_D("IINLIM: VBUS appeared, entering WAIT_DPDM");
504→                pData->iinlimTimestamp = now;
505→                pData->iinlimState = IINLIM_STATE_WAIT_DPDM;
506→            }
507→            break;
508→
509→        case IINLIM_STATE_WAIT_DPDM:
510→            if (!vbusPresent) {
511→                LOG_D("IINLIM: VBUS lost during WAIT_DPDM, returning to IDLE");
512→                pData->iinlimState = IINLIM_STATE_IDLE;
513→                break;
514→            }
515→            {
516→                TickType_t elapsed = now - pData->iinlimTimestamp;
517→
518→                // Wait at least 1s after VBUS before acting on DPDM result
519→                // to ensure BQ24297 hardware has fully settled
520→                if (elapsed < pdMS_TO_TICKS(1000)) {
521→                    break;
522→                }
523→
524→                // Check REG07 bit 7 for DPDM in progress
525→                uint8_t reg07 = BQ24297_Read_I2C(0x07);
526→                bool dpdmDone = (reg07 != 0xFF) && !(reg07 & 0x80);
527→                bool timeout = elapsed >= pdMS_TO_TICKS(3000);
528→
529→                if (dpdmDone) {
530→                    // DPDM finished — safe to set IINLIM, hardware won't overwrite
531→                    if (BQ24297_SetIINLIM(ILim_500)) {
532→                        LOG_D("IINLIM: DPDM done after %lu ms, set 500mA, entering WAIT_USB",
533→                              (unsigned long)(elapsed * portTICK_PERIOD_MS));
534→                        pData->iinlimTimestamp = now;
535→                        pData->iinlimState = IINLIM_STATE_WAIT_USB;
536→                    } else {
537→                        LOG_E("IINLIM: Failed to set 500mA, retrying next cycle");
538→                    }
539→                } else if (timeout) {
540→                    // DPDM stuck after 3s — set IINLIM anyway
541→                    LOG_E("IINLIM: DPDM not complete after 3s (REG07=0x%02X), forcing 500mA",
542→                          reg07);
543→                    if (BQ24297_SetIINLIM(ILim_500)) {
544→                        pData->iinlimTimestamp = now;
545→                        pData->iinlimState = IINLIM_STATE_WAIT_USB;
546→                    } else {
547→                        LOG_E("IINLIM: Failed to set 500mA on timeout, retrying next cycle");
548→                    }
549→                }
550→            }
551→            break;
552→
553→        case IINLIM_STATE_WAIT_USB:
554→            if (!vbusPresent) {
555→                BQ24297_SetIINLIM(ILim_500);
556→                LOG_D("IINLIM: VBUS lost during WAIT_USB, reset to 500mA");
557→                pData->iinlimState = IINLIM_STATE_IDLE;
558→                break;
559→            }
560→            if ((now - pData->iinlimTimestamp) >= pdMS_TO_TICKS(2000)) {
561→                if (UsbCdc_IsConfigured()) {
562→                    // USB host enumerated — keep 500mA (USB-spec safe)
563→                    LOG_D("IINLIM: USB configured, keeping 500mA");
564→                    pData->iinlimState = IINLIM_STATE_SETTLED;
565→                } else {
566→                    // No USB enumeration — wall charger, bump to 2000mA
567→                    if (BQ24297_SetIINLIM(ILim_2000)) {
568→                        LOG_D("IINLIM: No USB config, set 2000mA (wall charger)");
569→                        pData->iinlimState = IINLIM_STATE_SETTLED;
570→                    } else {
571→                        LOG_E("IINLIM: Failed to set 2000mA, retrying next cycle");
572→                    }
573→                }
574→            }
575→            break;
576→
577→        case IINLIM_STATE_SETTLED:
578→            if (!vbusPresent) {
579→                BQ24297_SetIINLIM(ILim_500);
580→                LOG_D("IINLIM: VBUS lost, reset to 500mA");
581→                pData->iinlimState = IINLIM_STATE_IDLE;
582→            }
583→            break;
584→
585→        default:
586→            pData->iinlimState = IINLIM_STATE_IDLE;
587→            break;
588→    }
589→
590→    pData->iinlimLastVbus = vbusPresent;
591→}
592→
593→void BQ24297_EnableOTG(void) {
594→    // Read REG08 for safety checks
595→    uint8_t reg08 = BQ24297_Read_I2C(0x08);
596→    bool pgStat = (reg08 >> 2) & 0x01;
597→    uint8_t vbusStat = (reg08 >> 6) & 0x03;
598→    
599→    // Clear HIZ mode if active
600→    uint8_t reg00 = BQ24297_Read_I2C(0x00);
601→    if (reg00 & 0x80) {
602→        reg00 &= 0x7F;  // Clear bit 7 (HIZ)
603→        BQ24297_Write_I2C(0x00, reg00);
604→        vTaskDelay(5 / portTICK_PERIOD_MS);
605→    }
606→    
607→    // Cannot enable OTG if external power is present
608→    if (pgStat) {
609→        return;
610→    }
611→    
612→    // Check if OTG is already active
613→    if (vbusStat == 0x03) {
614→        uint8_t reg01 = BQ24297_Read_I2C(0x01);
615→        if (reg01 & 0x20) {
616→            pData->status.otg = true;
617→            pData->status.chgEn = false;
618→            return;
619→        }
620→    }
621→    
622→    // Set OTG GPIO HIGH to enable boost mode
623→    BATT_MAN_OTG_OutputEnable();
624→    BATT_MAN_OTG_Set();
625→    
626→    // Read current REG01 value
627→    uint8_t reg01 = BQ24297_Read_I2C(0x01);
628→    if (reg01 == 0xFF) {
629→        return;
630→    }
631→    
632→    // Configure REG01 for OTG mode
633→    // Bit 5 = 1 (OTG enable), Bit 4 = 0 (charge disable), Bit 6 = 1 (watchdog reset)
634→    reg01 = (reg01 & 0x0F) | 0x60;
635→    
636→    // Write with retry logic
637→    bool success = false;
638→    for (int retry = 0; retry < 3; retry++) {
639→        if (BQ24297_Write_I2C(0x01, reg01)) {
640→            vTaskDelay(5 / portTICK_PERIOD_MS);
641→            
642→            // Verify write
643→            uint8_t readback = BQ24297_Read_I2C(0x01);
644→            if ((readback & 0x30) == 0x20) {  // Check OTG=1, CHG=0
645→                success = true;
646→                break;
647→            }
648→        }
649→        vTaskDelay(10 / portTICK_PERIOD_MS);
650→    }
651→    
652→    if (!success) {
653→        BATT_MAN_OTG_Clear();  // Clear GPIO on failure
654→    }
655→    
656→    // Update status
657→    pData->status.otg = success;
658→    pData->status.chgEn = false;
659→}
660→
661→void BQ24297_DisableOTG(bool enableCharging) {
662→    // Clear HIZ mode if active
663→    uint8_t reg00 = BQ24297_Read_I2C(0x00);
664→    if (reg00 != 0xFF && (reg00 & 0x80)) {
665→        reg00 &= 0x7F;  // Clear bit 7
666→        BQ24297_Write_I2C(0x00, reg00);
667→        vTaskDelay(2 / portTICK_PERIOD_MS);
668→    }
669→    
670→    // Set GPIO LOW to disable OTG
671→    BATT_MAN_OTG_OutputEnable();
672→    BATT_MAN_OTG_Clear();
673→    vTaskDelay(2 / portTICK_PERIOD_MS);
674→    
675→    // Read and modify REG01
676→    uint8_t reg = BQ24297_Read_I2C(0x01);
677→    if (reg == 0xFF) {
678→        pData->status.otg = false;
679→        return;
680→    }
681→    
682→    // Clear OTG bit (bit 5), set watchdog reset (bit 6)
683→    // Keep SYS_MIN at 3.0V (bits 3:1 = 000)
684→    reg = (reg & 0b11010001) | 0b01000001;
685→    
686→    // Set charge enable if requested
687→    if (enableCharging) {
688→        reg |= 0b00010000;
689→    }
690→    
691→    // Write the new value
692→    if (!BQ24297_Write_I2C(0x01, reg)) {
693→        return;
694→    }
695→    
696→    // Check for HIZ mode after REG01 write
697→    vTaskDelay(5 / portTICK_PERIOD_MS);
698→    reg00 = BQ24297_Read_I2C(0x00);
699→    if (reg00 != 0xFF && (reg00 & 0x80)) {
700→        reg00 &= 0x7F;
701→        BQ24297_Write_I2C(0x00, reg00);
702→    }
703→    
704→    // Update local status
705→    pData->status.otg = false;
706→    pData->status.chgEn = (reg & 0x10) ? true : false;
707→    
708→    // Give the BQ24297 time to perform input detection
709→    vTaskDelay(50 / portTICK_PERIOD_MS);
710→    
711→    // Update status to reflect changes
712→    BQ24297_UpdateStatus();
713→}
714→
715→bool BQ24297_IsOTGEnabled(void) {
716→    uint8_t reg = BQ24297_Read_I2C(0x01);
717→    return (reg & 0b00100000) != 0;
718→}
719→
720→bool BQ24297_IsChargingEnabled(void) {
721→    uint8_t reg = BQ24297_Read_I2C(0x01);
722→    return (reg & 0b00010000) != 0;
723→}
724→
725→bool BQ24297_IsBatteryPresent(void) {
726→    // Battery detection logic:
727→    // 1. If thermistor reads COLD (open circuit), battery is disconnected
728→    // 2. If thermistor reads HOT, it's stuck low (shorted) - battery may be present but charging unsafe
729→    // 3. Normal thermistor AND voltage > 3.0V indicates battery present
730→    
731→    // Update status to get latest NTC and voltage readings
732→    BQ24297_UpdateStatus();
733→    
734→    // NTC_FAULT_COLD (2) = thermistor open = no battery
735→    if (pData->status.ntcFault == NTC_FAULT_COLD) {
736→        return false;
737→    }
738→    
739→    // NTC_FAULT_HOT (1) = thermistor shorted/stuck low - unsafe to charge
740→    if (pData->status.ntcFault == NTC_FAULT_HOT) {
741→        // Battery might be present but thermistor is faulty
742→        // Check voltage to confirm battery presence
743→        return !pData->status.vsysStat;  // Battery present if voltage > 3.0V
744→    }
745→    
746→    // Normal thermistor reading - battery is present
747→    return true;
748→}
749→
750→void BQ24297_UpdateBatteryStatus(void) {
751→    bool oldBatPresent = pData->status.batPresent;
752→    bool oldChargeAllowed = pData->chargeAllowed;
753→
754→    pData->status.batPresent = BQ24297_IsBatteryPresent();
755→    pData->chargeAllowed = pData->status.batPresent &&
756→                           (pData->status.ntcFault != NTC_FAULT_HOT);
757→
758→    // Enforce charge state via I2C when chargeAllowed changes
759→    if (pData->chargeAllowed != oldChargeAllowed) {
760→        BQ24297_ChargeEnable(pData->chargeAllowed);
761→        LOG_D("BQ24297: Charging %s",
762→              pData->chargeAllowed ? "enabled" : "disabled");
763→    }
764→
765→    if (oldBatPresent != pData->status.batPresent) {
766→        LOG_D("BQ24297: Battery %s",
767→              pData->status.batPresent ? "detected" : "not detected");
768→    }
769→}
770→
771→void BQ24297_SetPowerMode(bool externalPowerPresent) {
772→    static bool lastExternalPowerState = false;
773→    static bool initialized = false;
774→
775→    // Only log when state actually changes
776→    if (!initialized || lastExternalPowerState != externalPowerPresent) {
777→        if (externalPowerPresent) {
778→            LOG_D("BQ24297_SetPowerMode: External power detected");
779→        } else {
780→            LOG_D("BQ24297_SetPowerMode: Battery power only");
781→        }
782→        lastExternalPowerState = externalPowerPresent;
783→        initialized = true;
784→    }
785→
786→    // OTG mode is disabled by default in the BQ24297 and set to disabled at init.
787→    // Charging is always enabled and handled autonomously by the hardware.
788→    // No action needed here - just logging state changes above.
789→}
