        (pBQ24297Data->status.inLim < 8) ? iLimStr[pBQ24297Data->status.inLim] : "Unknown",
        pBQ24297Data->status.otg ? "On" : "Off",
        otgGpioState ? "High" : "Low");
    context->interface->write(context, buffer, strlen(buffer));

