// Skip REG09 in the loop — it's a latched register that needs double-read protocol
uint8_t regs[11];
int errCount = 0;
for (int i = 0; i < 11; i++) {
    if (i == 9) continue;  // REG09 handled separately below
    regs[i] = BQ24297_Read_I2C(i);
    if (regs[i] == 0xFF) errCount++;
}

