uint8_t regs[11];
bool regOk[11];
int errCount = 0;
for (int i = 0; i < 11; i++) {
    if (i == 9) { regOk[i] = false; continue; }  // REG09 handled separately below
    regOk[i] = BQ24297_Read_I2C(i, &regs[i]);
    if (!regOk[i]) errCount++;
}

