/**
 * SCPI Callback: Get OTG status
 * Query: SYST:POW:OTG?
 * Returns: 0 (disabled) or 1 (enabled)
 */
static scpi_result_t SCPI_GetOTGMode(scpi_t * context) {
    bool otg_enabled = BQ24297_IsOTGEnabled();
    SCPI_ResultInt32(context, otg_enabled ? 1 : 0);
    return SCPI_RES_OK;
}
