/**
 * Gets the battery level
 * Returns -1 if device is in standby (battery monitoring inactive)
 * @param context
 * @return 
 */
static scpi_result_t SCPI_BatteryLevelGet(scpi_t * context) {
    tPowerData *pPowerData = BoardData_Get(
            BOARDDATA_POWER_DATA,
