 */

static scpi_result_t SCPI_SysInfoGet(scpi_t * context) {
    int param1;
    tBoardData * pBoardData = BoardData_Get(BOARDDATA_ALL_DATA, 0);

    if (!SCPI_ParamInt32(context, &param1, FALSE)) {
        param1 = 0;
