        return SCPI_RES_ERR;
    }

    if (param == 1) {
        LOG_D("SCPI: Manually enabling OTG mode");
        BQ24297_EnableOTG();
    } else {
        LOG_D("SCPI: Manually disabling OTG mode");
        BQ24297_DisableOTG(true);
    }

    return SCPI_RES_OK;
}

