    int param1;
    if (!SCPI_ParamInt32(context, &param1, TRUE)) {
        return SCPI_RES_ERR;
    }
    if (param1 == 0) {
        UsbCdc_SetTransparentMode(false);
    } else {
        UsbCdc_SetTransparentMode(true);
    }
    return SCPI_RES_OK;
}

